use crate::config;
use cor24_emulator::{EmulatorCore, StopReason};
use gloo::timers::callback::Timeout;
use std::collections::VecDeque;
use web_sys::HtmlDivElement;
use yew::prelude::*;

const PROMPT: &str = "      ";

/// Execution batch size per tick (instructions).
const BATCH_SIZE: u64 = 50_000;

/// Tick interval in milliseconds.
const TICK_MS: u32 = 25;

pub enum Msg {
    KeyDown(KeyboardEvent),
    Init,
    Tick,
}

/// Command counter — when the parent bumps the counter, we act.
#[derive(Properties, PartialEq)]
pub struct ReplPanelProps {
    /// Bumped by parent to trigger a reset.
    #[prop_or_default]
    pub reset_seq: u32,
    /// Text to feed as a demo program (set when demo_seq changes).
    #[prop_or_default]
    pub feed_text: AttrValue,
    /// Bumped by parent when feed_text should be consumed.
    #[prop_or_default]
    pub feed_seq: u32,
    /// S2 switch state.
    #[prop_or_default]
    pub s2_on: bool,
    /// Callback to report hardware state each tick: (led_on, last_tx, last_rx).
    #[prop_or_default]
    pub on_hw_state: Callback<(bool, Option<u8>, Option<u8>)>,
}

pub struct ReplPanel {
    emulator: EmulatorCore,
    output: Vec<String>,
    input: String,
    running: bool,
    halted: bool,
    uart_rx_queue: VecDeque<u8>,
    /// Partial line buffer for UART output that hasn't ended with '\n' yet.
    partial_line: String,
    _tick_handle: Option<Timeout>,
    output_ref: NodeRef,
    /// Track which reset_seq we last processed.
    last_reset_seq: u32,
    /// Track which feed_seq we last processed.
    last_feed_seq: u32,
    /// Last TX byte seen.
    last_tx: Option<u8>,
    /// Last RX byte seen.
    last_rx: Option<u8>,
}

impl ReplPanel {
    fn schedule_tick(ctx: &Context<Self>) -> Timeout {
        let link = ctx.link().clone();
        Timeout::new(TICK_MS, move || link.send_message(Msg::Tick))
    }

    fn scroll_to_bottom(&self) {
        if let Some(el) = self.output_ref.cast::<HtmlDivElement>() {
            el.set_scroll_top(el.scroll_height());
        }
    }

    /// Load the pre-assembled APL binary and start the emulator.
    fn load_apl_binary(&mut self) {
        let binary = config::APL_BINARY;
        self.emulator.hard_reset();
        self.emulator.set_uart_tx_busy_cycles(0);
        self.emulator.load_program(0, binary);
        self.emulator.load_program_extent(binary.len() as u32);
        self.emulator.set_pc(0);
        self.emulator.resume();
        self.running = true;
        self.halted = false;
        self.output.clear();
        self.partial_line.clear();
        self.uart_rx_queue.clear();
        self.last_tx = None;
        self.last_rx = None;
    }

    /// Feed bytes from the RX queue into the emulator UART while it's ready.
    fn feed_uart_bytes(&mut self) {
        while !self.uart_rx_queue.is_empty() {
            let status = self.emulator.read_byte(0xFF0101);
            if status & 0x01 != 0 {
                break; // RX buffer full, try again next tick
            }
            if let Some(byte) = self.uart_rx_queue.pop_front() {
                self.emulator.send_uart_byte(byte);
                self.last_rx = Some(byte);
            }
        }
    }

    /// Collect UART output from the emulator and append to the output buffer.
    fn collect_uart(&mut self) {
        let uart = self.emulator.get_uart_output();
        if uart.is_empty() {
            return;
        }
        let uart = uart.to_string();
        self.emulator.clear_uart_output();

        // Track last TX byte
        if let Some(b) = uart.bytes().last() {
            self.last_tx = Some(b);
        }

        // Split on newlines, handling partial lines across ticks.
        for ch in uart.chars() {
            if ch == '\n' {
                self.output.push(std::mem::take(&mut self.partial_line));
            } else if ch != '\r' {
                self.partial_line.push(ch);
            }
        }
    }

    /// Queue text to be sent to the interpreter line-by-line.
    fn feed_program_text(&mut self, text: &str) {
        for line in text.lines() {
            let trimmed = line.trim();
            if trimmed.is_empty() {
                continue;
            }
            for b in trimmed.bytes() {
                self.uart_rx_queue.push_back(b);
            }
            self.uart_rx_queue.push_back(b'\n');
        }
    }
}

impl Component for ReplPanel {
    type Message = Msg;
    type Properties = ReplPanelProps;

    fn create(ctx: &Context<Self>) -> Self {
        ctx.link().send_message(Msg::Init);
        let mut emulator = EmulatorCore::new();
        emulator.set_uart_tx_busy_cycles(0);
        Self {
            emulator,
            output: vec!["APL / COR24 Environment".to_string(), String::new()],
            input: String::new(),
            running: false,
            halted: false,
            uart_rx_queue: VecDeque::new(),
            partial_line: String::new(),
            _tick_handle: None,
            output_ref: NodeRef::default(),
            last_reset_seq: 0,
            last_feed_seq: 0,
            last_tx: None,
            last_rx: None,
        }
    }

    fn changed(&mut self, ctx: &Context<Self>, _old_props: &Self::Properties) -> bool {
        let props = ctx.props();

        // Handle reset command
        if props.reset_seq != self.last_reset_seq {
            self.last_reset_seq = props.reset_seq;
            self.load_apl_binary();
            if self._tick_handle.is_none() {
                self._tick_handle = Some(Self::schedule_tick(ctx));
            }
        }

        // Handle feed text command
        if props.feed_seq != self.last_feed_seq {
            self.last_feed_seq = props.feed_seq;
            self.feed_program_text(&props.feed_text);
        }

        // S2 switch — write to emulator's switch register
        // (The emulator reads switch state from a memory-mapped register)
        let s2_val = if props.s2_on { 1u8 } else { 0u8 };
        self.emulator.write_byte(0xFF0200, s2_val);

        true
    }

    fn update(&mut self, ctx: &Context<Self>, msg: Self::Message) -> bool {
        match msg {
            Msg::Init => {
                self.load_apl_binary();
                self._tick_handle = Some(Self::schedule_tick(ctx));
                true
            }
            Msg::Tick => {
                if !self.running || self.halted {
                    return false;
                }

                self.feed_uart_bytes();
                let result = self.emulator.run_batch(BATCH_SIZE);
                self.collect_uart();

                if matches!(result.reason, StopReason::Halted) {
                    self.halted = true;
                    self.running = false;
                }

                if self.running && !self.halted {
                    self._tick_handle = Some(Self::schedule_tick(ctx));
                }

                // Report hardware state to parent
                let led_on = self.emulator.read_byte(0xFF0000) != 0;
                ctx.props()
                    .on_hw_state
                    .emit((led_on, self.last_tx, self.last_rx));

                true
            }
            Msg::KeyDown(e) => {
                // Let modifier combos (Cmd-C, Ctrl-V, etc.) pass through to browser
                if e.meta_key() || e.ctrl_key() || e.alt_key() {
                    return false;
                }
                let key = e.key();
                match key.as_str() {
                    "Enter" => {
                        e.prevent_default();
                        // Show the input line in output
                        let line = format!("{PROMPT}{}", self.input);
                        self.output.push(line);
                        // Queue input bytes for the emulator's UART
                        for b in self.input.bytes() {
                            self.uart_rx_queue.push_back(b);
                        }
                        self.uart_rx_queue.push_back(b'\n');
                        self.input.clear();
                        true
                    }
                    "Backspace" => {
                        e.prevent_default();
                        self.input.pop();
                        true
                    }
                    _ => {
                        if key.len() == 1 {
                            e.prevent_default();
                            let ch = key.chars().next().unwrap();
                            if ch.is_ascii_graphic() || ch == ' ' {
                                self.input.push(ch);
                                return true;
                            }
                        }
                        false
                    }
                }
            }
        }
    }

    fn rendered(&mut self, _ctx: &Context<Self>, _first_render: bool) {
        self.scroll_to_bottom();
    }

    fn view(&self, ctx: &Context<Self>) -> Html {
        let onkeydown = ctx.link().callback(Msg::KeyDown);
        let cursor_class = if self.cursor_visible {
            "repl-cursor"
        } else {
            "repl-cursor repl-cursor-hidden"
        };

        html! {
            <div class="repl-panel" tabindex="0" {onkeydown}>
                <div class="repl-output" ref={self.output_ref.clone()}>
                    { for self.output.iter().map(|line| html! {
                        <div class="repl-line">{ line }</div>
                    })}
                    // Show partial line if the emulator is mid-output
                    if !self.partial_line.is_empty() {
                        <div class="repl-line">{ &self.partial_line }</div>
                    }
                    <div class="repl-input-line">
                        <span class="repl-prompt">{ PROMPT }</span>
                        <span class="repl-input-text">{ &self.input }</span>
                        <span class={cursor_class}>{"\u{2588}"}</span>
                    </div>
                </div>
            </div>
        }
    }
}

/* APL Environment styles */

#main-content {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
    position: relative;
}

/* Control bar */
.control-bar {
    display: flex;
    align-items: center;
    gap: 8px;
    padding: 8px 16px;
    border-bottom: 1px solid var(--surface1);
    background: var(--mantle);
    flex-shrink: 0;
}

.btn {
    font-family: var(--mono);
    font-size: 13px;
    padding: 4px 12px;
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
    background: var(--surface0);
    color: var(--text);
    transition: background 0.15s;
}

.btn:hover {
    background: var(--surface1);
}

.btn-reset {
    color: var(--red);
    border-color: var(--red);
}

.btn-upload {
    color: var(--blue);
    border-color: var(--blue);
}

.demo-select {
    font-family: var(--mono);
    font-size: 12px;
    padding: 3px 6px;
    background: var(--surface0);
    color: var(--text);
    border: 1px solid var(--surface2);
    border-radius: 4px;
    cursor: pointer;
}

/* REPL panel */
.repl-panel {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-height: 0;
    outline: none;
}

.repl-panel:focus {
    outline: none;
}

.repl-output {
    flex: 1;
    overflow-y: auto;
    padding: 12px 16px;
    background: var(--base);
    font-family: var(--mono);
    font-size: 15px;
    line-height: 1.5;
    color: var(--green);
    white-space: pre-wrap;
    word-break: break-all;
}

.repl-line {
    min-height: 1.5em;
}

.repl-input-line {
    display: inline;
}

.repl-prompt {
    color: var(--blue);
}

.repl-input-text {
    color: var(--text);
}

.repl-cursor {
    color: var(--text);
    animation: cursor-blink 1.06s step-end infinite;
}

.repl-cursor-hidden {
    visibility: hidden;
}

/* Hardware panel — floating bottom-right */
.hw-panel {
    position: absolute;
    bottom: 12px;
    right: 16px;
    background: rgba(24, 24, 37, 0.9);
    border: 1px solid var(--surface1);
    border-radius: 6px;
    padding: 10px 14px;
    font-family: var(--mono);
    font-size: 12px;
    color: var(--subtext0);
    z-index: 10;
    min-width: 140px;
}

.hw-title {
    font-size: 11px;
    font-weight: 600;
    color: var(--overlay1);
    text-transform: uppercase;
    letter-spacing: 0.05em;
    margin-bottom: 8px;
}

.hw-row {
    display: flex;
    align-items: center;
    gap: 8px;
    margin-bottom: 6px;
}

.hw-row:last-child {
    margin-bottom: 0;
}

.hw-label {
    color: var(--overlay2);
    min-width: 20px;
}

.hw-label-rx {
    margin-left: 8px;
}

/* D2 LED */
.hw-led {
    width: 12px;
    height: 12px;
    border-radius: 50%;
    display: inline-block;
}

.hw-led-on {
    background: var(--green);
    box-shadow: 0 0 6px var(--green);
}

.hw-led-off {
    background: var(--surface0);
    border: 1px solid var(--surface1);
}

/* S2 switch */
.hw-switch {
    padding: 2px 8px;
    border-radius: 3px;
    cursor: pointer;
    font-size: 11px;
    font-weight: 600;
    user-select: none;
}

.hw-switch-on {
    background: var(--blue);
    color: var(--base);
}

.hw-switch-off {
    background: var(--surface0);
    color: var(--overlay1);
    border: 1px solid var(--surface1);
}

.hw-switch:hover {
    opacity: 0.85;
}

.hw-byte {
    font-size: 12px;
    color: var(--text);
}

/* Cursor blink animation */
@keyframes cursor-blink {
    0%, 49% { opacity: 1; }
    50%, 100% { opacity: 0; }
}

/* Responsive: narrow viewports */
@media (max-width: 600px) {
    .control-bar {
        flex-wrap: wrap;
        padding: 6px 10px;
        gap: 6px;
    }

    .hw-panel {
        position: static;
        margin: 0 10px 8px;
        border-radius: 4px;
    }

    .repl-output {
        padding: 8px 10px;
        font-size: 13px;
    }
}

@media (max-width: 400px) {
    .btn {
        font-size: 12px;
        padding: 3px 8px;
    }

    .demo-select {
        font-size: 11px;
        width: 100%;
    }
}

